import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - single main item base premium", () => {
    it.todo("should return processing fee only for empty item list for a first-time customer with no loyalty");
    it.todo("should compute premium for a single sword (base 100 G) for a first-time non-loyal customer");
    it.todo("should compute premium for a single amulet (base 60 G) for a first-time non-loyal customer");
    it.todo("should compute premium for a single staff (base 80 G) for a first-time non-loyal customer");
    it.todo("should compute premium for a single potion (base 40 G) for a first-time non-loyal customer");
  });

  describe("quote - single component base premium", () => {
    it.todo("should compute premium for a single rune (base 25 G) for a first-time non-loyal customer");
    it.todo("should compute premium for a single moonstone (base 25 G) for a first-time non-loyal customer");
  });

  describe("quote - multiple items sum base premiums", () => {
    it.todo("should sum base premiums for two different main items");
    it.todo("should sum base premiums for a main item and a component");
  });

  describe("quote - component bundling (3 alike = 60 G)", () => {
    it.todo("should price a bundle of 3 alike runes at 60 G instead of 75 G");
    it.todo("should price a bundle of 3 alike moonstones at 60 G instead of 75 G");
    it.todo("should not bundle 2 alike components (still 50 G total)");
    it.todo("should bundle 3 alike and price the 4th separately (60 G + 25 G)");
    it.todo("should bundle two separate triples of alike components independently (3 runes + 3 moonstones)");
    it.todo("should not bundle across different component types (1 rune + 2 moonstones = 75 G)");
  });

  describe("quote - per-item modifiers", () => {
    it.todo("should apply +50% risk surcharge to a cursed item");
    it.todo("should apply +30% risk surcharge to a highly enchanted item (enchantment >= 5)");
    it.todo("should not apply enchantment surcharge below the threshold (enchantment 4)");
    it.todo("should apply both cursed and high-enchantment surcharges to the same item");
  });

  describe("quote - customer-level modifiers", () => {
    it.todo("should apply +10% initial assessment surcharge on the customer's first quote");
    it.todo("should apply -15% subsequent-contract discount on the second quote onward");
    it.todo("should apply -20% loyalty discount for long-standing customers (yearsWithMHPCO >= 2)");
    it.todo("should not apply loyalty discount below the threshold (yearsWithMHPCO = 1)");
  });

  describe("quote - processing fee and rounding", () => {
    it.todo("should add a flat 5 G processing fee to every premium");
    it.todo("should round the premium up to the nearest whole G (MHPCO's favor)");
  });

  describe("claim - basic payout rules", () => {
    it.todo("should subtract the 100 G deductible from a standard damage amount");
    it.todo("should pay out 0 when the damage amount is at or below the 100 G deductible");
    it.todo("should reimburse 50% of the damage for items with enchantment >= 8 (after deductible)");
    it.todo("should fully reimburse damage to items made of dragon material (no deductible)");
    it.todo("should sum payouts across multiple damaged items in a single incident, applying the deductible once per event");
  });

  describe("CLI integration via quote/claim API", () => {
    it.todo("should process a scenario with a single quote step and return its premium");
    it.todo("should process a scenario with a quote followed by a claim referencing the policy by index");
    it.todo("should process multiple sequential quotes applying the first/subsequent-contract modifiers correctly");
  });
});
